'use server'

import { createClient } from '@/lib/supabase/server'
import { revalidatePath } from 'next/cache'

export async function getTeamMembers() {
    const supabase = await createClient()

    // Basic query to fetch profiles
    // Check hierarchy logic if needed, for MVP we fetch all if admin

    const { data, error } = await supabase
        .from('profiles')
        .select('*')
        .order('created_at', { ascending: false })

    if (error) {
        console.error('Error fetching team:', error)
        return []
    }

    return data
}

// NOTE: Creating users usually requires calling supabase.auth.admin.createUser
// which is only available in environments with SERVICE_ROLE_KEY.
// The legacy app uses Edge Functions ('create-team-user').
// We can either port that logic to a Next.js API Route (using service key) 
// or call the existing Edge Function from here.
// For now, we will assume we call the existing Edge Function via the Supabase Client.

export async function deleteTeamMember(userId: string) {
    const supabase = await createClient()

    // Assuming we use the same edge function approach or simple delete if cascade works
    // But usually we need to delete from auth.users too which requires Service Role.
    // We'll leave this as a placeholder or call RPC if available.

    // Fallback: Delete profile (might trigger something)
    const { error } = await supabase
        .from('profiles')
        .delete()
        .eq('id', userId)

    // NOTE: This won't delete Auth User without trigger/Edge Function
    if (error) throw new Error(error.message)
    revalidatePath('/team')
}
